// // This module compares two 64-bit numbers and outputs whether the first is less than or equal to the second.
module comparator_64bit (
    input [63:0] A,
    input [63:0] B,
    output reg A_gt_B,
    output reg A_lt_B,
    output reg A_eq_B
);

always @(*) begin
    if (A > B) begin
        A_gt_B = 1;
        A_lt_B = 0;
        A_eq_B = 0;
    end else if (A < B) begin
        A_gt_B = 0;
        A_lt_B = 1;
        A_eq_B = 0;
    end else begin
        A_gt_B = 0;
        A_lt_B = 0;
        A_eq_B = 1;
    end
end

endmodule
